Функция СальдоСчета(СчетСсылка) Экспорт
    ВидСчета = СчетСсылка.Вид;

    Запрос = Новый Запрос;
    Запрос.Текст = "ВЫБРАТЬ ЕСТЬNULL(СУММА(Хозрасчетный.Сумма), 0) КАК ОборотДт
                   |ИЗ РегистрБухгалтерии.Хозрасчетный КАК Хозрасчетный
                   |ГДЕ Хозрасчетный.СчетДт В ИЕРАРХИИ(&Счет)";
    Запрос.УстановитьПараметр("Счет", СчетСсылка);
    Результат = Запрос.Выполнить();
    Выборка = Результат.Выбрать();
    Выборка.Следующий();
    ОборотДт = Выборка.ОборотДт;

    Запрос2 = Новый Запрос;
    Запрос2.Текст = "ВЫБРАТЬ ЕСТЬNULL(СУММА(Хозрасчетный.Сумма), 0) КАК ОборотКт
                    |ИЗ РегистрБухгалтерии.Хозрасчетный КАК Хозрасчетный
                    |ГДЕ Хозрасчетный.СчетКт В ИЕРАРХИИ(&Счет)";
    Запрос2.УстановитьПараметр("Счет", СчетСсылка);
    Результат2 = Запрос2.Выполнить();
    Выборка2 = Результат2.Выбрать();
    Выборка2.Следующий();
    ОборотКт = Выборка2.ОборотКт;

    Если ВидСчета = Перечисления.ВидыСчетов.Пассивный Тогда
        Сальдо = ОборотКт - ОборотДт;
    Иначе
        Сальдо = ОборотДт - ОборотКт;
    КонецЕсли;

    Возврат Сальдо;
КонецФункции
